{
  "grammar": [
    {
      "pattern": "在 + company/place + 工作/上課/上班",
      "structure": ["在", "place", "verb"],
      "explanation_en": "Use 在 to indicate the location where an action (like working or studying) takes place.",
      "title": "在 for Location of Work/Study",
      "meaning": "Indicates where someone works or studies.",
      "when_to_use": ["When specifying the company or school where you work or study", "When answering 'Where do you work/study?'"],
      "when_not_to_use": ["Do not use 在 for the object of work (e.g., 'I work on a project')", "Do not use 在 for time expressions like 'at 9 o'clock'"],
      "pragmatic_notes": "In Taiwan, it's common to say 我在公司上班 or 我在學校上課. You can also specify the company name: 我在台積電工作.",
      "word_order_notes": "在 + place + verb. The place comes before the action verb.",
      "english_contrast": "English says 'I work at a company' (verb + at + place). Chinese reverses the order: 我在公司工作 (place + verb).",
      "korean_contrast": "Korean uses '에서' (e.g., 회사에서 일해요). Chinese uses 在 + place + verb, similar structure but without a separate particle.",
      "negative_examples": [
        {
          "text": "我工作在公司。",
          "error": "Word order is wrong. 在 must come before the verb, not after."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我工作在公司。",
          "error": "The place should come before the verb: 我在公司工作。"
        }
      ],
      "transformation_drills": ["Change 'I study at school' to 'I work at a company' using 在.", "Change 'He works at a hospital' to 'She studies at a university'."],
      "production_drills": ["Answer: 你在哪裡工作？", "Answer: 你在哪裡上課？"],
      "common_error_patterns": ["Placing 在 after the verb", "Omitting 在 entirely"],
      "repair_feedback": {
        "word_order": "Remember: 在 + place + verb, not verb + 在 + place.",
        "politeness": "This structure is neutral and polite.",
        "vocabulary": "Use 工作 for work, 上課 for study, 上班 for going to work."
      }
    },
    {
      "pattern": "當 + role (e.g., 老師, 學生, 老闆)",
      "structure": ["當", "role"],
      "explanation_en": "Use 當 to express 'to work as' or 'to be' a certain role or profession.",
      "title": "當 for Roles and Professions",
      "meaning": "Indicates one's role or profession.",
      "when_to_use": ["When stating your job title or role", "When asking about someone's profession"],
      "when_not_to_use": ["Do not use 當 for temporary states (e.g., 'I am hungry')", "Do not use 當 for nationality (e.g., 'I am Taiwanese')"],
      "pragmatic_notes": "In Taiwan, 當 is very common: 我當老師, 他當老闆. It's more specific than just 是.",
      "word_order_notes": "當 + role. The role comes directly after 當.",
      "english_contrast": "English uses 'work as' or 'be a'. Chinese uses 當 + role directly.",
      "korean_contrast": "Korean uses '으로 일하다' (e.g., 선생님으로 일해요). Chinese uses 當 + role, simpler.",
      "negative_examples": [
        {
          "text": "我當在學校老師。",
          "error": "Do not add location between 當 and the role. Use 在 separately."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我當在學校老師。",
          "error": "Should be: 我在學校當老師。"
        }
      ],
      "transformation_drills": ["Change 'I am a student' to 'I work as a teacher' using 當.", "Change 'He is a boss' to 'She is a colleague'."],
      "production_drills": ["Answer: 你當什麼？", "Answer: 你媽媽當什麼？"],
      "common_error_patterns": ["Using 是 instead of 當 for roles", "Adding extra words between 當 and the role"],
      "repair_feedback": {
        "word_order": "當 + role directly, no extra words in between.",
        "politeness": "Neutral and polite.",
        "vocabulary": "Use 當 for roles like 老師, 學生, 老闆, 同事."
      }
    },
    {
      "pattern": "忙不忙？ / 忙 / 不忙",
      "structure": ["subject", "忙不忙", "or", "忙", "or", "不忙"],
      "explanation_en": "Use 忙不忙 to ask if someone is busy. Answer with 忙 (busy) or 不忙 (not busy).",
      "title": "忙不忙 for Busyness",
      "meaning": "Asks or states whether someone is busy.",
      "when_to_use": ["When asking about someone's schedule", "When responding to 'Are you busy?'"],
      "when_not_to_use": ["Do not use 忙 for things (e.g., 'This task is busy')", "Do not use 忙不忙 for yes/no questions about other adjectives"],
      "pragmatic_notes": "In Taiwan, 你忙不忙？ is a common polite way to start a conversation about scheduling. Answer with 很忙 or 不忙.",
      "word_order_notes": "Subject + 忙不忙？ Answer: Subject + 忙 or 不忙.",
      "english_contrast": "English uses 'Are you busy?' Chinese uses 你忙不忙？ (literally 'you busy not busy').",
      "korean_contrast": "Korean uses '바쁘세요?' Chinese uses 忙不忙, a different structure.",
      "negative_examples": [
        {
          "text": "你忙嗎？",
          "error": "This is also correct, but 忙不忙 is more common for casual questions."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你忙不忙嗎？",
          "error": "Do not add 嗎 after 忙不忙. 忙不忙 already forms a question."
        }
      ],
      "transformation_drills": ["Change 'Are you busy?' to 'Is he busy?' using 忙不忙.", "Change 'I am busy' to 'I am not busy'."],
      "production_drills": ["Ask a classmate: 你忙不忙？", "Answer: 我忙 / 我不忙."],
      "common_error_patterns": ["Adding 嗎 after 忙不忙", "Using 忙 for objects instead of people"],
      "repair_feedback": {
        "word_order": "忙不忙 is a fixed phrase for asking about busyness.",
        "politeness": "Polite and casual.",
        "vocabulary": "Use 忙 for people, not for things."
      }
    }
  ]
}
